 94→export function createInitialSketchEditorState(activeLayerId = null) {
 95→  return {
 96→    activeTool: SKETCH_TOOLS.SELECT,
 97→    selectedId: null,
 98→    selectedType: null,
 99→    toolState: {},
100→    viewport: { panX: 400, panY: 300, zoom: DEFAULT_SKETCH_ZOOM },
101→    activeLayerId,
102→    activeObjectId: null,
103→    showGrid: true,
104→    snapEnabled: true,
105→    statusMessage: null,
106→    emptyStateDismissed: false,
107→  };
108→}
109→
110→export function SketchEditorProvider({ children, initialActiveLayerId = null }) {
111→  const [state, dispatch] = useReducer(
112→    sketchEditorReducer,
113→    initialActiveLayerId,
114→    createInitialSketchEditorState
115→  );
116→
117→  return (
118→    <SketchEditorContext.Provider value={{ state, dispatch }}>
119→      {children}
120→    </SketchEditorContext.Provider>
121→  );
122→}
123→
124→export function useSketchEditor() {
125→  const ctx = useContext(SketchEditorContext);
126→  if (!ctx) throw new Error('useSketchEditor must be used within SketchEditorProvider');
127→  return { ...ctx.state, dispatch: ctx.dispatch };
128→}
