 1→export { SKETCH_TOOLS } from '../domain/defaults';
 2→
 3→export const SKETCH_TOOL_SHORTCUTS = {
 4→  v: 'select',
 5→  r: 'rectangle',
 6→  e: 'ellipse',
 7→  l: 'line',
 8→  p: 'pen',
 9→};
