  1→function RectShape({ shape }) {
  2→  return (
  3→    <rect
  4→      x={shape.x}
  5→      y={shape.y}
  6→      width={shape.width}
  7→      height={shape.height}
  8→      fill={shape.fill}
  9→      stroke={shape.stroke}
 10→      strokeWidth={shape.strokeWidth}
 11→      transform={shape.rotation ? `rotate(${shape.rotation} ${shape.x + shape.width / 2} ${shape.y + shape.height / 2})` : undefined}
 12→    />
 13→  );
 14→}
 15→
 16→function EllipseShape({ shape }) {
 17→  const cx = shape.x + shape.width / 2;
 18→  const cy = shape.y + shape.height / 2;
 19→  const rx = Math.abs(shape.width) / 2;
 20→  const ry = Math.abs(shape.height) / 2;
 21→
 22→  return (
 23→    <ellipse
 24→      cx={cx}
 25→      cy={cy}
 26→      rx={rx}
 27→      ry={ry}
 28→      fill={shape.fill}
 29→      stroke={shape.stroke}
 30→      strokeWidth={shape.strokeWidth}
 31→      transform={shape.rotation ? `rotate(${shape.rotation} ${cx} ${cy})` : undefined}
 32→    />
 33→  );
 34→}
 35→
 36→function LineShape({ shape }) {
 37→  const points = shape.points;
 38→  if (points.length < 2) return null;
 39→
 40→  return (
 41→    <line
 42→      x1={points[0].x}
 43→      y1={points[0].y}
 44→      x2={points[1].x}
 45→      y2={points[1].y}
 46→      stroke={shape.stroke}
 47→      strokeWidth={shape.strokeWidth}
 48→      strokeLinecap="round"
 49→    />
 50→  );
 51→}
 52→
 53→function PathShape({ shape }) {
 54→  const points = shape.points;
 55→  if (points.length < 2) return null;
 56→
 57→  const d = points.reduce((acc, pt, i) => {
 58→    if (i === 0) return `M ${pt.x} ${pt.y}`;
 59→    return `${acc} L ${pt.x} ${pt.y}`;
 60→  }, '');
 61→
 62→  return (
 63→    <path
 64→      d={d}
 65→      fill={shape.fill}
 66→      stroke={shape.stroke}
 67→      strokeWidth={shape.strokeWidth}
 68→      strokeLinecap="round"
 69→      strokeLinejoin="round"
 70→    />
 71→  );
 72→}
 73→
 74→const shapeComponents = {
 75→  rect: RectShape,
 76→  ellipse: EllipseShape,
 77→  line: LineShape,
 78→  path: PathShape,
 79→};
 80→
 81→export default function ShapeRenderer({ shape, isSelected = false, zoom = 1 }) {
 82→  const Component = shapeComponents[shape.type];
 83→  if (!Component) return null;
 84→
 85→  return (
 86→    <g data-shape-id={shape.id}>
 87→      <Component shape={shape} />
 88→      {isSelected && (
 89→        <rect
 90→          x={shape.x - 4 / zoom}
 91→          y={shape.y - 4 / zoom}
 92→          width={(shape.width || 0) + 8 / zoom}
 93→          height={(shape.height || 0) + 8 / zoom}
 94→          fill="none"
 95→          stroke="var(--color-workspace-sketch, #B8860B)"
 96→          strokeWidth={1.5 / zoom}
 97→          strokeDasharray={`${4 / zoom} ${3 / zoom}`}
 98→          style={{ pointerEvents: 'none' }}
 99→        />
100→      )}
101→    </g>
102→  );
103→}
